import asyncio
import aiosqlite
import aiohttp
from aiogram.client.session.aiohttp import AiohttpSession

from scripts.fill_heroes import fill_heroes


async def fill_tarot():
    async with aiosqlite.connect('heroes.db') as db:
        async with db.execute("SELECT COUNT(*) FROM heroes") as cursor:
            hero_count = await cursor.fetchone()

        if hero_count[0] == 0:
            print("⚠️ Герои не найдены в БД. Загружаем из API...")
            await fill_heroes()

            async with db.execute("SELECT COUNT(*) FROM heroes") as cursor:
                hero_count = await cursor.fetchone()

            if hero_count[0] == 0:
                print("❌ Не удалось загрузить героев!")
                return

