        updated_count = 0
        not_found_count = 0

        for localized_name, tarot_name, roles, prediction, advice in updates:
            cursor = await db.execute(
                """
                UPDATE heroes 
                SET tarot_name = ?, 
                    roles = ?, 
                    prediction = ?, 
                    advice = ?
                WHERE localized_name = ?
                """,
                (tarot_name, roles, prediction, advice, localized_name)
            )

            if cursor.rowcount > 0:
                updated_count += 1
                print(f"✅ Обновлен: {localized_name}")
            else:
                not_found_count += 1
                print(f"❌ Не найден: {localized_name}")

        await db.commit()

        print(f"\n📊 Итоги:")
        print(f"   - Обновлено героев: {updated_count}")
        print(f"   - Не найдено: {not_found_count}")

        async with db.execute("SELECT COUNT(*) FROM heroes WHERE tarot_name IS NOT NULL") as cursor:
            filled = await cursor.fetchone()
            print(f"   - Всего с заполненными картами Таро: {filled[0]}")


